import copy
import json

def apply_patch(document, patches):
    """Apply a list of JSON Patch operations (RFC 6902 subset) to a document.
    Supports: add, remove, replace operations.
    Path format: '/key/index/nested' (JSON Pointer, RFC 6901)
    Returns the modified document.
    """
    result = copy.deepcopy(document)

    def unescape_json_pointer(token):
        """Unescape JSON Pointer token according to RFC 6901"""
        return token.replace('~1', '/').replace('~0', '~')

    def parse_json_pointer(path):
        """Parse JSON Pointer path into tokens"""
        if path == '':
            return []
        if not path.startswith('/'):
            raise ValueError("JSON Pointer must start with '/'")
        if path == '/':
            return ['']
        return [unescape_json_pointer(token) for token in path[1:].split('/')]

    for patch in patches:
        op = patch['op']
        path = patch['path']
        value = patch.get('value')

        # Parse JSON pointer
        parts = parse_json_pointer(path)

        # Handle root document operations
        if len(parts) == 0:
            if op == 'replace':
                result = value
            elif op == 'remove':
                raise ValueError("Cannot remove root document")
            elif op == 'add':
                raise ValueError("Cannot add to root document")
            continue

        # Navigate to parent
        parent = result
        for part in parts[:-1]:
            if isinstance(parent, list):
                try:
                    index = int(part)
                    if index < 0 or index >= len(parent):
                        raise IndexError("Array index out of bounds")
                    parent = parent[index]
                except ValueError:
                    raise ValueError(f"Invalid array index: {part}")
            elif isinstance(parent, dict):
                if part not in parent:
                    raise KeyError(f"Key not found: {part}")
                parent = parent[part]
            else:
                raise ValueError("Cannot navigate through non-container type")

        target = parts[-1]

        if op == 'add':
            if isinstance(parent, list):
                if target == '-':
                    parent.append(value)
                else:
                    try:
                        index = int(target)
                        if index < 0 or index > len(parent):
                            raise IndexError("Array index out of bounds for add")
                        parent.insert(index, value)
                    except ValueError:
                        raise ValueError(f"Invalid array index: {target}")
            elif isinstance(parent, dict):
                parent[target] = value
            else:
                raise ValueError("Cannot add to non-container type")

        elif op == 'remove':
            if isinstance(parent, list):
                try:
                    index = int(target)
                    if index < 0 or index >= len(parent):
                        raise IndexError("Array index out of bounds")
                    del parent[index]
                except ValueError:
                    raise ValueError(f"Invalid array index: {target}")
            elif isinstance(parent, dict):
                if target not in parent:
                    raise KeyError(f"Key not found: {target}")
                del parent[target]
            else:
                raise ValueError("Cannot remove from non-container type")

        elif op == 'replace':
            if isinstance(parent, list):
                try:
                    index = int(target)
                    if index < 0 or index >= len(parent):
                        raise IndexError("Array index out of bounds")
                    parent[index] = value
                except ValueError:
                    raise ValueError(f"Invalid array index: {target}")
            elif isinstance(parent, dict):
                if target not in parent:
                    raise KeyError(f"Key not found: {target}")
                parent[target] = value
            else:
                raise ValueError("Cannot replace in non-container type")

    return result

class EventEmitter:
    def __init__(self):
        self._listeners = {}  # event_name -> list of callbacks

    def on(self, event, callback):
        """Register a listener for an event."""
        if event not in self._listeners:
            self._listeners[event] = []
        self._listeners[event].append(callback)

    def off(self, event, callback):
        """Remove a listener for an event."""
        if event in self._listeners:
            try:
                self._listeners[event].remove(callback)
            except ValueError:
                pass  # Callback not found, ignore

    def emit(self, event, *args, **kwargs):
        """Emit an event, calling all registered listeners."""
        if event not in self._listeners:
            return
        # Create a copy of the listeners list to avoid iterator invalidation
        listeners_copy = self._listeners[event][:]
        for listener in listeners_copy:
            # Check if listener is still in the original list before calling
            if listener in self._listeners[event]:
                listener(*args, **kwargs)

    def listener_count(self, event):
        """Return number of listeners for an event."""
        return len(self._listeners.get(event, []))

import threading
from collections import deque


class Connection:
    """Simulated database connection."""
    _counter = 0
    _lock = threading.Lock()

    def __init__(self):
        with Connection._lock:
            Connection._counter += 1
            self.id = Connection._counter
        self.closed = False

    def execute(self, query):
        if self.closed:
            raise RuntimeError('Connection is closed')
        return f'Result of {query} on conn {self.id}'

    def close(self):
        self.closed = True


class ConnectionPool:
    """A simple connection pool with a fixed size."""
    def __init__(self, max_size=5):
        self.max_size = max_size
        self._pool = deque()
        self._in_use = set()
        self._lock = threading.Lock()
        # Pre-fill pool
        for _ in range(max_size):
            self._pool.append(Connection())

    def acquire(self):
        """Get a connection from the pool."""
        with self._lock:
            if not self._pool:
                raise RuntimeError('No connections available')
            conn = self._pool.popleft()
            self._in_use.add(conn)
            return conn

    def release(self, conn):
        """Return a connection to the pool."""
        with self._lock:
            if conn in self._in_use:
                self._in_use.remove(conn)
                self._pool.append(conn)

    def __enter__(self):
        self._current_conn = self.acquire()
        return self._current_conn

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.release(self._current_conn)
        return False

    @property
    def available(self):
        with self._lock:
            return len(self._pool)

    @property
    def in_use_count(self):
        with self._lock:
            return len(self._in_use)

def compare_versions(v1, v2):
    """Compare two semver strings. Returns:
    -1 if v1 < v2
     0 if v1 == v2
     1 if v1 > v2
    Handles pre-release versions per semver spec.
    """
    def parse(v):
        # Remove leading 'v' if present
        if v.lower().startswith('v'):
            v = v[1:]

        # Remove build metadata (everything after '+')
        if '+' in v:
            v = v.split('+')[0]

        # Split off pre-release
        if '-' in v:
            main, pre = v.split('-', 1)
        else:
            main, pre = v, None

        parts = list(map(int, main.split('.')))
        return parts, pre

    main1, pre1 = parse(v1)
    main2, pre2 = parse(v2)

    # Compare main version
    for a, b in zip(main1, main2):
        if a < b:
            return -1
        if a > b:
            return 1

    if len(main1) != len(main2):
        return -1 if len(main1) < len(main2) else 1

    # Compare pre-release
    if pre1 is None and pre2 is None:
        return 0
    if pre1 is None:
        return 1  # No pre-release > pre-release
    if pre2 is None:
        return -1  # Pre-release < no pre-release

    # Compare pre-release identifiers
    ids1 = pre1.split('.')
    ids2 = pre2.split('.')

    for a, b in zip(ids1, ids2):
        # Both numeric
        if a.isdigit() and b.isdigit():
            if int(a) != int(b):
                return -1 if int(a) < int(b) else 1
        # Numeric < non-numeric
        elif a.isdigit():
            return -1
        elif b.isdigit():
            return 1
        else:
            # Lexical comparison
            if a < b:
                return -1
            if a > b:
                return 1

    # All compared identifiers are equal, shorter pre-release is less
    if len(ids1) != len(ids2):
        return -1 if len(ids1) < len(ids2) else 1

    return 0

def glob_match(pattern, text):
    """Match a glob pattern against text.
    Supports:
    - * matches any sequence of characters (except /)
    - ? matches any single character
    - {a,b,c} matches any of the alternatives (can be nested)
    - \\ escapes the next character
    Returns True if the entire text matches the pattern.
    """
    def _expand_braces(pattern):
        """Expand brace expressions and return list of expanded patterns."""
        # Find first '{'
        start = pattern.find('{')
        if start == -1:
            return [pattern]

        # Find matching '}' by counting braces
        brace_count = 0
        end = -1
        i = start
        while i < len(pattern):
            if pattern[i] == '\\':
                # Skip escaped character
                i += 2
                continue
            elif pattern[i] == '{':
                brace_count += 1
            elif pattern[i] == '}':
                brace_count -= 1
                if brace_count == 0:
                    end = i
                    break
            i += 1

        if end == -1:
            return [pattern]

        prefix = pattern[:start]
        suffix = pattern[end + 1:]

        # Parse alternatives, respecting nested braces
        alternatives = []
        current_alt = ""
        brace_count = 0
        i = start + 1

        while i < end:
            if pattern[i] == '\\':
                # Add escaped character as-is
                current_alt += pattern[i:i+2]
                i += 2
                continue
            elif pattern[i] == '{':
                brace_count += 1
                current_alt += pattern[i]
            elif pattern[i] == '}':
                brace_count -= 1
                current_alt += pattern[i]
            elif pattern[i] == ',' and brace_count == 0:
                # This comma is at the top level, so it separates alternatives
                alternatives.append(current_alt)
                current_alt = ""
                i += 1
                continue
            else:
                current_alt += pattern[i]
            i += 1

        # Add the last alternative
        alternatives.append(current_alt)

        results = []
        for alt in alternatives:
            for expanded in _expand_braces(prefix + alt + suffix):
                results.append(expanded)
        return results

    def _match(pattern, text):
        pi = 0
        ti = 0
        while pi < len(pattern) and ti < len(text):
            if pattern[pi] == '\\':
                pi += 1
                if pi < len(pattern) and ti < len(text) and pattern[pi] == text[ti]:
                    pi += 1
                    ti += 1
                else:
                    return False
            elif pattern[pi] == '?':
                pi += 1
                ti += 1
            elif pattern[pi] == '*':
                # Try matching zero or more characters
                pi += 1
                for end in range(ti, len(text) + 1):
                    if _match(pattern[pi:], text[end:]):
                        return True
                return False
            elif pattern[pi] == text[ti]:
                pi += 1
                ti += 1
            else:
                return False
        # Consume trailing *'s
        while pi < len(pattern) and pattern[pi] == '*':
            pi += 1
        return pi == len(pattern) and ti == len(text)

    # Expand braces first, then match each alternative
    for expanded in _expand_braces(pattern):
        if _match(expanded, text):
            return True
    return False

class IntervalTree:
    """Interval tree supporting insertion and point queries.
    Intervals are inclusive on both ends: [lo, hi].
    """
    class Node:
        def __init__(self, lo, hi, data):
            self.lo = lo
            self.hi = hi
            self.data = data
            self.max_hi = hi
            self.left = None
            self.right = None

    def __init__(self):
        self.root = None

    def insert(self, lo, hi, data):
        """Insert interval [lo, hi] with associated data."""
        self.root = self._insert(self.root, lo, hi, data)

    def _insert(self, node, lo, hi, data):
        if node is None:
            return self.Node(lo, hi, data)
        if lo < node.lo:
            node.left = self._insert(node.left, lo, hi, data)
        else:
            node.right = self._insert(node.right, lo, hi, data)
        node.max_hi = max(node.max_hi, hi)
        return node

    def query(self, point):
        """Return list of data for all intervals containing the point."""
        results = []
        self._query(self.root, point, results)
        return results

    def _query(self, node, point, results):
        if node is None:
            return
        # If point is to the left of this node's interval, no need to check right
        if point < node.lo:
            self._query(node.left, point, results)
            return
        # Check if point is in this node's interval
        if node.lo <= point <= node.hi:  # FIXED: now includes right endpoint
            results.append(node.data)
        # Check left subtree if it could contain matching intervals
        if node.left and node.left.max_hi >= point:  # FIXED: now includes equality
            self._query(node.left, point, results)
        # Check right subtree
        self._query(node.right, point, results)

    def query_range(self, lo, hi):
        """Return list of data for all intervals that overlap with [lo, hi]."""
        results = []
        self._query_range(self.root, lo, hi, results)
        return results

    def _query_range(self, node, lo, hi, results):
        if node is None:
            return
        if node.lo <= hi and lo <= node.hi:
            results.append(node.data)
        if node.left and node.left.max_hi >= lo:
            self._query_range(node.left, lo, hi, results)
        if node.right and node.lo <= hi:
            self._query_range(node.right, lo, hi, results)

class WildcardTrie:
    def __init__(self):
        self.children = {}
        self.is_end = False
        self._words = []  # Track all words for verification

    def insert(self, word):
        self._words.append(word)
        node = self
        for ch in word:
            if ch not in node.children:
                node.children[ch] = WildcardTrie()
            node = node.children[ch]
        node.is_end = True

    def search(self, pattern):
        """Search for pattern where '.' matches any character."""
        return self._search(self, pattern, 0)

    def _search(self, node, pattern, index):
        if index == len(pattern):
            return node.is_end

        ch = pattern[index]
        if ch == '.':
            # Try each child
            for child_key in list(node.children.keys()):
                if self._search(node.children[child_key], pattern, index + 1):
                    return True
            return False
        else:
            child = node.children.get(ch)
            if child is None:
                return False
            return self._search(child, pattern, index + 1)

    def get_all_words(self):
        """Return all inserted words."""
        return self._words[:]

    def starts_with(self, prefix):
        """Return True if any word starts with the given prefix."""
        node = self
        for ch in prefix:
            if ch not in node.children:
                return False
            node = node.children[ch]
        # Check if there's any word that starts with this prefix
        return self._has_words_below(node)

    def _has_words_below(self, node):
        """Check if there are any complete words in the subtree rooted at node."""
        if node.is_end:
            return True
        for child in node.children.values():
            if self._has_words_below(child):
                return True
        return False

    def delete(self, word):
        """Delete a word from the trie."""
        if word in self._words:
            self._words.remove(word)
            self._delete(self, word, 0)

    def _delete(self, node, word, index):
        """Delete a word and return True if the current node should be deleted."""
        if index == len(word):
            node.is_end = False
            # Return True if this node has no children and is not end of another word
            return len(node.children) == 0 and not node.is_end

        ch = word[index]
        if ch not in node.children:
            return False  # Word doesn't exist

        should_delete_child = self._delete(node.children[ch], word, index + 1)

        if should_delete_child:
            del node.children[ch]

        # Return True if current node should be deleted
        # (has no children, is not end of word, and we're not at root)
        return len(node.children) == 0 and not node.is_end and node is not self

from collections import deque

def topo_sort(edges):
    """Topological sort of a directed graph.
    edges: list of (from_node, to_node) tuples
    Returns a list of nodes in topological order.
    Raises ValueError if the graph contains a cycle.
    """
    if not edges:
        return []

    graph = {}
    in_degree = {}
    all_nodes = set()

    # Collect all nodes
    for src, dst in edges:
        all_nodes.add(src)
        all_nodes.add(dst)

    # Initialize graph and in-degrees
    for node in all_nodes:
        graph[node] = set()
        in_degree[node] = 0

    # Build graph and calculate in-degrees
    for src, dst in edges:
        graph[src].add(dst)  # Set automatically deduplicates parallel edges

    # Calculate in-degrees from deduplicated graph
    for node in graph:
        for neighbor in graph[node]:
            in_degree[neighbor] += 1

    queue = deque(sorted([n for n in all_nodes if in_degree[n] == 0]))
    result = []

    while queue:
        node = queue.popleft()
        result.append(node)
        for neighbor in graph[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    if len(result) != len(all_nodes):
        raise ValueError('Graph contains a cycle')

    return result
